contracts/DisputeCourt.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

interface IWorkEscrow {
    function releaseToWorker(bytes32 jobId, uint256 amount) external;

    function refundEmployer(bytes32 jobId) external;

    function getEscrow(bytes32 jobId)
        external
        view
        returns (
            uint256 amount,
            address employer,
            address worker,
            bool released,
            bool refunded,
            uint256 createdAt
        );
}

interface IJobRegistry {
    function getJob(bytes32 jobId)
        external
        view
        returns (
            bytes32,
            address,
            address,
            uint256,
            uint256,
            uint256,
            bool,
            string memory,
            string memory,
            uint256
        );
}

contract DisputeCourt is Ownable, ReentrancyGuard {
    struct Dispute {
        bytes32 disputeId;
        bytes32 jobId;
        address opener;
        string reason;
        string openedBy; // 'worker' or 'employer'
        bool resolved;
        string resolution; // 'worker_paid' or 'employer_refunded'
        uint256 createdAt;
        uint256 resolvedAt;
    }

    struct Ruling {
        address judge;
        bool hasRuled;
        string decision; // 'worker' or 'employer'
    }

    IWorkEscrow public workEscrow;
    IJobRegistry public jobRegistry;

    mapping(address => bool) public verifiedJudges;
    mapping(bytes32 => Dispute) public disputes;
    mapping(bytes32 => address[]) public disputeJudges;
    mapping(bytes32 => mapping(address => Ruling)) public rulings;

    uint256 public totalDisputes = 0;

    event DisputeOpened(
        bytes32 indexed disputeId,
        bytes32 indexed jobId,
        address opener,
        string reason
    );

    event JudgeVerified(address indexed judge);

    event RulingSubmitted(
        bytes32 indexed disputeId,
        address indexed judge,
        string decision
    );

    event DisputeResolved(
        bytes32 indexed disputeId,
        bytes32 indexed jobId,
        string resolution
    );

    constructor(address _workEscrow, address _jobRegistry)
        Ownable(msg.sender)
    {
        workEscrow = IWorkEscrow(_workEscrow);
        jobRegistry = IJobRegistry(_jobRegistry);
    }

    function registerJudge(address judge) external onlyOwner {
        require(judge != address(0), "Invalid judge");
        verifiedJudges[judge] = true;
        emit JudgeVerified(judge);
    }

    function openDispute(
        bytes32 jobId,
        string calldata reason,
        string calldata openedBy
    ) external returns (bytes32) {
        require(
            keccak256(abi.encodePacked(openedBy)) ==
                keccak256(abi.encodePacked("worker")) ||
                keccak256(abi.encodePacked(openedBy)) ==
                keccak256(abi.encodePacked("employer")),
            "Invalid opener"
        );

        bytes32 disputeId = keccak256(
            abi.encodePacked(jobId, msg.sender, block.timestamp)
        );

        disputes[disputeId] = Dispute({
            disputeId: disputeId,
            jobId: jobId,
            opener: msg.sender,
            reason: reason,
            openedBy: openedBy,
            resolved: false,
            resolution: "",
            createdAt: block.timestamp,
            resolvedAt: 0
        });

        totalDisputes++;

        emit DisputeOpened(disputeId, jobId, msg.sender, reason);

        return disputeId;
    }

    function submitRuling(bytes32 disputeId, string calldata decision)
        external
        nonReentrant
    {
        require(verifiedJudges[msg.sender], "Not a verified judge");

        Dispute storage dispute = disputes[disputeId];
        require(!dispute.resolved, "Dispute already resolved");

        Ruling storage ruling = rulings[disputeId][msg.sender];
        require(!ruling.hasRuled, "Judge already ruled");

        ruling.judge = msg.sender;
        ruling.hasRuled = true;
        ruling.decision = decision;

        disputeJudges[disputeId].push(msg.sender);

        emit RulingSubmitted(disputeId, msg.sender, decision);

        // Check for 2/3 majority
        _checkResolution(disputeId);
    }

    function _checkResolution(bytes32 disputeId) internal {
        Dispute storage dispute = disputes[disputeId];
        require(!dispute.resolved, "Already resolved");

        address[] memory judges = disputeJudges[disputeId];

        if (judges.length < 2) {
            return; // Need at least 2 judges
        }

        uint256 workerVotes = 0;
        uint256 employerVotes = 0;

        for (uint256 i = 0; i < judges.length; i++) {
            string memory decision = rulings[disputeId][judges[i]].decision;

            if (
                keccak256(abi.encodePacked(decision)) ==
                keccak256(abi.encodePacked("worker"))
            ) {
                workerVotes++;
            } else if (
                keccak256(abi.encodePacked(decision)) ==
                keccak256(abi.encodePacked("employer"))
            ) {
                employerVotes++;
            }
        }

        // 2/3 majority required (at least 2 judges must agree)
        if (workerVotes >= 2 && workerVotes > employerVotes) {
            _resolveDispute(disputeId, "worker_paid");
        } else if (employerVotes >= 2 && employerVotes > workerVotes) {
            _resolveDispute(disputeId, "employer_refunded");
        }
    }

    function _resolveDispute(bytes32 disputeId, string memory resolution)
        internal
    {
        Dispute storage dispute = disputes[disputeId];
        dispute.resolved = true;
        dispute.resolution = resolution;
        dispute.resolvedAt = block.timestamp;

        (uint256 amount, address employer, address worker, , , ) = workEscrow
            .getEscrow(dispute.jobId);

        if (
            keccak256(abi.encodePacked(resolution)) ==
            keccak256(abi.encodePacked("worker_paid"))
        ) {
            workEscrow.releaseToWorker(dispute.jobId, amount);
        } else {
            workEscrow.refundEmployer(dispute.jobId);
        }

        emit DisputeResolved(disputeId, dispute.jobId, resolution);
    }

    function getDispute(bytes32 disputeId)
        external
        view
        returns (Dispute memory)
    {
        return disputes[disputeId];
    }

    function getDisputeJudges(bytes32 disputeId)
        external
        view
        returns (address[] memory)
    {
        return disputeJudges[disputeId];
    }

    function getRuling(bytes32 disputeId, address judge)
        external
        view
        returns (Ruling memory)
    {
        return rulings[disputeId][judge];
    }

    function isJudgeVerified(address judge) external view returns (bool) {
        return verifiedJudges[judge];
    }
}

contracts/JobRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

contract JobRegistry is Ownable, ReentrancyGuard {
    struct Job {
        bytes32 jobId;
        address employer;
        address worker;
        uint256 dailyRateUSDC;
        uint256 startDate;
        uint256 endDate;
        bool active;
        string hederaTopicId;
        string location;
        uint256 createdAt;
    }

    mapping(bytes32 => Job) public jobs;
    mapping(address => bool) public verifiedEmployers;
    mapping(address => bytes32[]) public employerJobs;
    mapping(address => bytes32[]) public workerJobs;

    event JobCreated(
        bytes32 indexed jobId,
        address indexed employer,
        uint256 dailyRate,
        string location,
        uint256 startDate,
        uint256 endDate
    );

    event WorkerAssigned(bytes32 indexed jobId, address indexed worker);

    event JobCompleted(bytes32 indexed jobId, address indexed worker);

    event EmployerVerified(address indexed employer);

    event JobCanceled(bytes32 indexed jobId);

    modifier onlyVerifiedEmployer(address employer) {
        require(verifiedEmployers[employer], "Employer not verified by World ID");
        _;
    }

    constructor() Ownable(msg.sender) {}

    function setEmployerVerified(address employer) external onlyOwner {
        require(employer != address(0), "Invalid employer address");
        verifiedEmployers[employer] = true;
        emit EmployerVerified(employer);
    }

    function createJob(
        uint256 dailyRateUSDC,
        uint256 startDate,
        uint256 endDate,
        string calldata location
    ) external onlyVerifiedEmployer(msg.sender) returns (bytes32) {
        require(dailyRateUSDC > 0, "Rate must be > 0");
        require(startDate < endDate, "Invalid dates");
        require(startDate >= block.timestamp, "Start date must be in future");

        bytes32 jobId = keccak256(
            abi.encodePacked(msg.sender, block.timestamp, block.number)
        );

        jobs[jobId] = Job({
            jobId: jobId,
            employer: msg.sender,
            worker: address(0),
            dailyRateUSDC: dailyRateUSDC,
            startDate: startDate,
            endDate: endDate,
            active: true,
            hederaTopicId: "",
            location: location,
            createdAt: block.timestamp
        });

        employerJobs[msg.sender].push(jobId);

        emit JobCreated(
            jobId,
            msg.sender,
            dailyRateUSDC,
            location,
            startDate,
            endDate
        );

        return jobId;
    }

    function assignWorker(bytes32 jobId, address worker) external {
        Job storage job = jobs[jobId];
        require(job.employer == msg.sender, "Only employer can assign");
        require(job.active, "Job not active");
        require(worker != address(0), "Invalid worker");

        job.worker = worker;
        workerJobs[worker].push(jobId);

        emit WorkerAssigned(jobId, worker);
    }

    function setHederaTopic(bytes32 jobId, string calldata topicId) external {
        Job storage job = jobs[jobId];
        require(
            job.employer == msg.sender || msg.sender == owner(),
            "Unauthorized"
        );
        job.hederaTopicId = topicId;
    }

    function completeJob(bytes32 jobId) external {
        Job storage job = jobs[jobId];
        require(job.active, "Job not active");
        require(job.employer == msg.sender, "Only employer can complete");
        require(job.worker != address(0), "No worker assigned");

        job.active = false;

        emit JobCompleted(jobId, job.worker);
    }

    function cancelJob(bytes32 jobId) external {
        Job storage job = jobs[jobId];
        require(job.employer == msg.sender, "Only employer can cancel");
        require(job.active, "Job not active");

        job.active = false;

        emit JobCanceled(jobId);
    }

    function getJob(bytes32 jobId) external view returns (Job memory) {
        return jobs[jobId];
    }

    function getEmployerJobs(address employer)
        external
        view
        returns (bytes32[] memory)
    {
        return employerJobs[employer];
    }

    function getWorkerJobs(address worker)
        external
        view
        returns (bytes32[] memory)
    {
        return workerJobs[worker];
    }

    function isEmployerVerified(address employer)
        external
        view
        returns (bool)
    {
        return verifiedEmployers[employer];
    }
}

contracts/WorkEscrow.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

interface IJobRegistry {
    function getJob(bytes32 jobId)
        external
        view
        returns (
            bytes32,
            address,
            address,
            uint256,
            uint256,
            uint256,
            bool,
            string memory,
            string memory,
            uint256
        );
}

contract WorkEscrow is Ownable, ReentrancyGuard {
    struct EscrowInfo {
        uint256 amount;
        address employer;
        address worker;
        bool released;
        bool refunded;
        uint256 createdAt;
    }

    IERC20 public usdc;
    IJobRegistry public jobRegistry;
    address public disrupteCourt;

    mapping(bytes32 => EscrowInfo) public escrows;
    mapping(bytes32 => uint256) public releasedAmounts;

    event FundsLocked(bytes32 indexed jobId, address employer, uint256 amount);
    event FundsReleased(
        bytes32 indexed jobId,
        address worker,
        uint256 amount
    );
    event FundsRefunded(bytes32 indexed jobId, address employer, uint256 amount);

    modifier onlyJobRegistry() {
        require(msg.sender == address(jobRegistry), "Only JobRegistry");
        _;
    }

    modifier onlyDisputeCourtOrJobRegistry() {
        require(
            msg.sender == disrupteCourt || msg.sender == address(jobRegistry),
            "Unauthorized"
        );
        _;
    }

    constructor(
        address _usdc,
        address _jobRegistry,
        address _disrupteCourt
    ) Ownable(msg.sender) {
        usdc = IERC20(_usdc);
        jobRegistry = IJobRegistry(_jobRegistry);
        disrupteCourt = _disrupteCourt;
    }

    function setDisputeCourt(address _disrupteCourt) external onlyOwner {
        disrupteCourt = _disrupteCourt;
    }

    function lockFunds(bytes32 jobId, uint256 amount)
        external
        nonReentrant
    {
        require(amount > 0, "Amount must be > 0");
        require(escrows[jobId].amount == 0, "Funds already locked");

        // Transfer USDC from employer to this contract
        bool success = usdc.transferFrom(msg.sender, address(this), amount);
        require(success, "Transfer failed");

        escrows[jobId] = EscrowInfo({
            amount: amount,
            employer: msg.sender,
            worker: address(0),
            released: false,
            refunded: false,
            createdAt: block.timestamp
        });

        emit FundsLocked(jobId, msg.sender, amount);
    }

    function releaseToWorker(bytes32 jobId, uint256 amount)
        external
        nonReentrant
        onlyDisputeCourtOrJobRegistry
    {
        EscrowInfo storage escrow = escrows[jobId];
        require(escrow.amount > 0, "No escrow found");
        require(!escrow.released, "Already released");
        require(!escrow.refunded, "Already refunded");
        require(amount <= escrow.amount, "Amount exceeds escrow");

        address worker = escrow.worker;
        require(worker != address(0), "No worker assigned");

        escrow.released = true;
        releasedAmounts[jobId] += amount;

        bool success = usdc.transfer(worker, amount);
        require(success, "Transfer failed");

        emit FundsReleased(jobId, worker, amount);
    }

    function refundEmployer(bytes32 jobId)
        external
        nonReentrant
        onlyDisputeCourtOrJobRegistry
    {
        EscrowInfo storage escrow = escrows[jobId];
        require(escrow.amount > 0, "No escrow found");
        require(!escrow.refunded, "Already refunded");

        escrow.refunded = true;

        uint256 refundAmount = escrow.amount - releasedAmounts[jobId];
        require(refundAmount > 0, "Nothing to refund");

        bool success = usdc.transfer(escrow.employer, refundAmount);
        require(success, "Transfer failed");

        emit FundsRefunded(jobId, escrow.employer, refundAmount);
    }

    function getEscrow(bytes32 jobId)
        external
        view
        returns (EscrowInfo memory)
    {
        return escrows[jobId];
    }

    function getReleasedAmount(bytes32 jobId) external view returns (uint256) {
        return releasedAmounts[jobId];
    }
}

